`timescale 1ns/1ns
`include "../common/define.sv"


module sm_core (
	input  clk,                                               // input clock for the system
	input  rst_n,                                             // reset signal to the system, negative active

	// code memory interface
	input  code_mem_ready_i,                                  // signal indicating whether external code memory is ready for access
	output code_rd_req_valid_o,                               // valid signal of code memory read operation
	output [`CODE_MEM_ADDR_WIDTH-1:0] code_rd_req_addr_o,     // code memory read address
	output [`DEPTH_WARP-1:0] code_rd_req_wid_o,               // warp id of code memory read 	
	input  code_rd_rsp_valid_i,                               // valid signal of code memory data after read operation
	input  [`CODE_MEM_ADDR_WIDTH-1:0] code_rd_rsp_addr_i,     // code memory read address
	input  [`DEPTH_WARP-1:0] code_rd_rsp_wid_i,               // warp id of code memory read 
    input  [`CODE_MEM_DATA_WIDTH-1:0] code_rd_rsp_data_i,     // data bits returned by code memory read operation


	// tpc interface
	output tpc_req_ready_o,                                   // signal telling whether sm core is ready to receive a new request from tpc
	input  tpc_req_valid_i,                                   // signal indicating a new kernel to be assigned to this sm core for execution
	input  [`CODE_ADDR_WIDTH-1:0] tpc_req_start_addr_i,       // starting address for kernel code

	input  tpc_rsp_ready_i,                                   // signal telling whether tpc is ready to receive the response from this sm core
	output tpc_rsp_valid_o,                                   // valid signal of sm core response to gpc
	output [`DEPTH_WARP-1:0] tpc_rsp_wid_o                    // warp id of the warp that has finished its execution
);

wire                            sm_warp_req_valid;
wire [`DEPTH_WARP-1:0]          sm_warp_req_wid;

wire sm_warp_rsp_ready, sm_warp_rsp_valid;
wire [`DEPTH_WARP-1:0]          sm_warp_rsp_wid;

wire [`NUM_WARP-1:0]            ibuffer_avail; 
wire [`NUM_WARP-1:0]            stalled_warps;
wire [`NUM_WARP-1:0]            ready_warps;

wire [`CODE_MEM_DATA_WIDTH-1:0] inst_to_decode;

wire [`CODE_MEM_DATA_WIDTH-1:0] decode_signals_inst;
wire [`DEPTH_WARP-1:0]          decode_signals_wid;
wire [3:0]                      decode_signals_opcode_na;
wire [5:0]                      decode_signals_mod;
wire [3:0]                      decode_signals_pr;
wire [5:0]                      decode_signals_dst;
wire [5:0]                      decode_signals_src1;
wire [19:0]                     decode_signals_immea;
wire [1:0]                      decode_signals_space_sel;
wire [9:0]                      decode_signals_immeb;
wire [5:0]                      decode_signals_opcode_nb;

wire [`CODE_MEM_DATA_WIDTH-1:0] ibuffer_signals_inst;
wire [`DEPTH_WARP-1:0]          ibuffer_signals_wid;
wire [3:0]                      ibuffer_signals_opcode_na;
wire [5:0]                      ibuffer_signals_mod;
wire [3:0]                      ibuffer_signals_pr;
wire [5:0]                      ibuffer_signals_dst;
wire [5:0]                      ibuffer_signals_src1;
wire [19:0]                     ibuffer_signals_immea;
wire [1:0]                      ibuffer_signals_space_sel;
wire [9:0]                      ibuffer_signals_immeb;
wire [5:0]                      ibuffer_signals_opcode_nb;
wire                            ibuffer_signals_valid;

wire                            operand_collect_in_ready;

wire [`CODE_MEM_DATA_WIDTH-1:0] sb_signals_inst;
wire [`DEPTH_WARP-1:0]          sb_signals_wid;
wire [3:0]                      sb_signals_opcode_na;
wire [5:0]                      sb_signals_mod;
wire [3:0]                      sb_signals_pr;
wire [5:0]                      sb_signals_dst;
wire [5:0]                      sb_signals_src1;
wire [19:0]                     sb_signals_immea;
wire [1:0]                      sb_signals_space_sel;
wire [9:0]                      sb_signals_immeb;
wire [5:0]                      sb_signals_opcode_nb;
wire                            sb_signals_valid;

wire                            wb_valid;
wire [`DEPTH_WARP-1:0]          wb_wid;
wire [5:0]                      wb_dst;
wire [`REG_DATA_WIDTH-1:0]      wb_data;

wire                            int_alu_valid;
wire [`DEPTH_WARP-1:0]          int_alu_wid;
wire [5:0]                      int_alu_dst;
wire [`REG_DATA_WIDTH-1:0]      int_alu_src1_data;
wire [`REG_DATA_WIDTH-1:0]      int_alu_src2_data;
wire [5:0]                      int_alu_opcode_nb;
wire [5:0]                      int_alu_mod;

wire [`CODE_MEM_DATA_WIDTH-1:0] oc_signals_inst;
wire [`DEPTH_WARP-1:0]          oc_signals_wid;
wire [3:0]                      oc_signals_opcode_na;
wire [5:0]                      oc_signals_mod;
wire [3:0]                      oc_signals_pr;
wire [5:0]                      oc_signals_dst;
wire [`REG_DATA_WIDTH-1:0]      oc_signals_src1_data;
wire [`REG_DATA_WIDTH-1:0]      oc_signals_src2_data;
wire [19:0]                     oc_signals_immea;
wire [1:0]                      oc_signals_space_sel;
wire [9:0]                      oc_signals_immeb;
wire [5:0]                      oc_signals_opcode_nb;
wire                            oc_signals_valid;

assign inst_to_decode = code_rd_rsp_data_i;

sm_warp_scheduler U_sm_warp_scheduler (
	.clk                         (clk),
	.rst_n                       (rst_n),	

	.tpc_req_ready_o             (tpc_req_ready_o),
	.tpc_req_valid_i             (tpc_req_valid_i),	
	.tpc_rsp_ready_i             (tpc_rsp_ready_i),
	.tpc_rsp_valid_o             (tpc_rsp_valid_o),
	.tpc_rsp_wid_o               (tpc_rsp_wid_o),

	.sm_warp_req_valid_o         (sm_warp_req_valid),
	.sm_warp_req_wid_o           (sm_warp_req_wid),
	.sm_warp_rsp_ready_o         (sm_warp_rsp_ready),
	.sm_warp_rsp_valid_i         (sm_warp_rsp_valid),
	.sm_warp_rsp_wid_i           (sm_warp_rsp_wid)
);

sm_fetch U_sm_fetch (
	.clk                         (clk),
	.rst_n                       (rst_n),

	.sm_warp_req_valid_i         (sm_warp_req_valid),
	.sm_warp_req_wid_i           (sm_warp_req_wid),
	.sm_warp_req_start_addr_i    (tpc_req_start_addr_i),
	.ibuffer_avail_i             (ibuffer_avail),
	.stalled_warps_i             (stalled_warps),
	.ready_warps_o               (ready_warps),

	.code_mem_ready_i            (code_mem_ready_i),
	.code_rd_req_valid_o         (code_rd_req_valid_o),
	.code_rd_req_addr_o          (code_rd_req_addr_o),
	.code_rd_req_wid_o           (code_rd_req_wid_o),

	.code_rd_rsp_valid_i         (code_rd_rsp_valid_i),
	.code_rd_rsp_addr_i          (code_rd_rsp_addr_i),
	.code_rd_rsp_wid_i           (code_rd_rsp_wid_i)
);

sm_decode U_sm_decode (
	.clk                         (clk),
	.rst_n                       (rst_n),

	.valid_i                     (code_rd_rsp_valid_i),
	.inst_i                      (inst_to_decode),
	.wid_i                       (code_rd_rsp_wid_i),

	.decode_signals_inst_o       (decode_signals_inst),
	.decode_signals_wid_o        (decode_signals_wid),
	.decode_signals_opcode_na_o  (decode_signals_opcode_na),
	.decode_signals_mod_o        (decode_signals_mod),
	.decode_signals_pr_o         (decode_signals_pr),
	.decode_signals_dst_o        (decode_signals_dst),
	.decode_signals_src1_o       (decode_signals_src1),
	.decode_signals_immea_o      (decode_signals_immea),
	.decode_signals_space_sel_o  (decode_signals_space_sel),
	.decode_signals_immeb_o      (decode_signals_immeb),	
	.decode_signals_opcode_nb_o  (decode_signals_opcode_nb)
);


sm_inst_buffer #(
	.IBUFFER_DATA_WIDTH(2*`CODE_MEM_DATA_WIDTH+`DEPTH_WARP),
	.IBUFFER_SIZE(2)
) U_sm_inst_buffer (
	.clk                          (clk),
	.rst_n                        (rst_n),

	.decode_signals_valid_i       (code_rd_rsp_valid_i),
	.decode_signals_inst_i        (decode_signals_inst),
	.decode_signals_wid_i         (decode_signals_wid),
	.decode_signals_opcode_na_i   (decode_signals_opcode_na),
	.decode_signals_mod_i         (decode_signals_mod),
	.decode_signals_pr_i          (decode_signals_pr),
	.decode_signals_dst_i         (decode_signals_dst),
	.decode_signals_src1_i        (decode_signals_src1),
	.decode_signals_immea_i       (decode_signals_immea),
	.decode_signals_space_sel_i   (decode_signals_space_sel),
	.decode_signals_immeb_i       (decode_signals_immeb),	
	.decode_signals_opcode_nb_i   (decode_signals_opcode_nb),

	.ibuffer_signals_inst_o       (ibuffer_signals_inst),
	.ibuffer_signals_wid_o        (ibuffer_signals_wid),
	.ibuffer_signals_opcode_na_o  (ibuffer_signals_opcode_na),
	.ibuffer_signals_mod_o        (ibuffer_signals_mod),                      
	.ibuffer_signals_pr_o         (ibuffer_signals_pr),                        
	.ibuffer_signals_dst_o        (ibuffer_signals_dst),                        
	.ibuffer_signals_src1_o       (ibuffer_signals_src1), 
	.ibuffer_signals_immea_o      (ibuffer_signals_immea), 
	.ibuffer_signals_space_sel_o  (ibuffer_signals_space_sel),
	.ibuffer_signals_immeb_o      (ibuffer_signals_immeb),
	.ibuffer_signals_opcode_nb_o  (ibuffer_signals_opcode_nb),
	.ibuffer_signals_valid_o      (ibuffer_signals_valid),

	.ready_warps_i                (ready_warps),
	.ibuffer_avail_o              (ibuffer_avail)
);

wire int_alu_wb_valid;
wire [`DEPTH_WARP-1:0] int_alu_wb_wid;
wire [5:0] int_alu_wb_dst;
wire [`REG_DATA_WIDTH-1:0] int_alu_wb_data;

sm_score_board U_sm_score_board (
	.clk                          (clk),
	.rst_n                        (rst_n),

	.ibuffer_signals_valid_i      (ibuffer_signals_valid),
	.ibuffer_signals_inst_i       (ibuffer_signals_inst),
	.ibuffer_signals_wid_i        (ibuffer_signals_wid),
	.ibuffer_signals_opcode_na_i  (ibuffer_signals_opcode_na),
	.ibuffer_signals_mod_i        (ibuffer_signals_mod),
	.ibuffer_signals_pr_i         (ibuffer_signals_pr),
	.ibuffer_signals_dst_i        (ibuffer_signals_dst),
	.ibuffer_signals_src1_i       (ibuffer_signals_src1),
	.ibuffer_signals_immea_i      (ibuffer_signals_immea),
	.ibuffer_signals_space_sel_i  (ibuffer_signals_space_sel),
	.ibuffer_signals_immeb_i      (ibuffer_signals_immeb),
	.ibuffer_signals_opcode_nb_i  (ibuffer_signals_opcode_nb),

	.wb_valid_i                   (wb_valid),
	.wb_wid_i                     (wb_wid),
	.wb_dst_i                     (wb_dst),

	.sb_signals_valid_o           (sb_signals_valid),
	.sb_signals_inst_o            (sb_signals_inst),
	.sb_signals_wid_o             (sb_signals_wid),
	.sb_signals_opcode_na_o       (sb_signals_opcode_na),
	.sb_signals_mod_o             (sb_signals_mod),
	.sb_signals_pr_o              (sb_signals_pr),
	.sb_signals_dst_o             (sb_signals_dst),
	.sb_signals_src1_o            (sb_signals_src1),
	.sb_signals_immea_o           (sb_signals_immea),
	.sb_signals_space_sel_o       (sb_signals_space_sel),
	.sb_signals_immeb_o           (sb_signals_immeb),
	.sb_signals_opcode_nb_o       (sb_signals_opcode_nb),

	.stalled_warps_o              (stalled_warps)
);
sm_operand_collect U_sm_operand_collect (
	.clk                          (clk),
	.rst_n                        (rst_n),

	.sb_signals_valid_i           (sb_signals_valid),
	.sb_signals_inst_i            (sb_signals_inst),
	.sb_signals_wid_i             (sb_signals_wid),
	.sb_signals_opcode_na_i       (sb_signals_opcode_na),
	.sb_signals_mod_i             (sb_signals_mod),
	.sb_signals_pr_i              (sb_signals_pr),
	.sb_signals_dst_i             (sb_signals_dst),
	.sb_signals_src1_i            (sb_signals_src1),
	.sb_signals_immea_i           (sb_signals_immea),
	.sb_signals_space_sel_i       (sb_signals_space_sel),
	.sb_signals_immeb_i           (sb_signals_immeb),
	.sb_signals_opcode_nb_i       (sb_signals_opcode_nb),

	.wb_valid_i                   (wb_valid),
	.wb_wid_i                     (wb_wid),
	.wb_dst_i                     (wb_dst),
	.wb_data_i                    (wb_data),

	.oc_signals_valid_o           (oc_signals_valid),
	.oc_signals_inst_o            (oc_signals_inst),
	.oc_signals_wid_o             (oc_signals_wid),
	.oc_signals_opcode_na_o       (oc_signals_opcode_na),
	.oc_signals_mod_o             (oc_signals_mod),
	.oc_signals_pr_o              (oc_signals_pr),
	.oc_signals_dst_o             (oc_signals_dst),
	.oc_signals_src1_data_o       (oc_signals_src1_data),
	.oc_signals_src2_data_o       (oc_signals_src2_data),
	.oc_signals_immea_o           (oc_signals_immea),
	.oc_signals_space_sel_o       (oc_signals_space_sel),
	.oc_signals_immeb_o           (oc_signals_immeb),
	.oc_signals_opcode_nb_o       (oc_signals_opcode_nb)
);
sm_issue U_sm_issue (
	.clk                          (clk),
	.rst_n                        (rst_n),

	.oc_signals_valid_i           (oc_signals_valid),
	.oc_signals_inst_i            (oc_signals_inst),
	.oc_signals_wid_i             (oc_signals_wid),
	.oc_signals_opcode_na_i       (oc_signals_opcode_na),
	.oc_signals_mod_i             (oc_signals_mod),
	.oc_signals_pr_i              (oc_signals_pr),
	.oc_signals_dst_i             (oc_signals_dst),
	.oc_signals_src1_data_i       (oc_signals_src1_data),
	.oc_signals_src2_data_i       (oc_signals_src2_data),
	.oc_signals_immea_i           (oc_signals_immea),
	.oc_signals_space_sel_i       (oc_signals_space_sel),
	.oc_signals_immeb_i           (oc_signals_immeb),
	.oc_signals_opcode_nb_i       (oc_signals_opcode_nb),

	.int_alu_valid_o              (int_alu_valid),
	.int_alu_wid_o                (int_alu_wid),
	.int_alu_dst_o                (int_alu_dst),
	.int_alu_src1_data_o          (int_alu_src1_data),
	.int_alu_src2_data_o          (int_alu_src2_data),
	.int_alu_opcode_nb_o          (int_alu_opcode_nb),
	.int_alu_mod_o                (int_alu_mod),

	.sm_warp_rsp_valid_o          (sm_warp_rsp_valid),
	.sm_warp_rsp_wid_o            (sm_warp_rsp_wid)
);

sm_int_alu U_sm_int_alu (
	.clk                          (clk),
	.rst_n                        (rst_n),

	.valid_i                      (int_alu_valid),
	.wid_i                        (int_alu_wid),
	.dst_i                        (int_alu_dst),
	.src1_data_i                  (int_alu_src1_data),
	.src2_data_i                  (int_alu_src2_data),
	.opcode_nb_i                  (int_alu_opcode_nb),
	.mod_i                        (int_alu_mod),

	.wb_valid_o                   (int_alu_wb_valid),
	.wb_wid_o                     (int_alu_wb_wid),
	.wb_dst_o                     (int_alu_wb_dst),
	.wb_data_o                    (int_alu_wb_data)
);

sm_writeback U_sm_writeback (
	.clk                          (clk),
	.rst_n                        (rst_n),

	.int_alu_wb_valid_i           (int_alu_wb_valid),
	.int_alu_wb_wid_i             (int_alu_wb_wid),
	.int_alu_wb_dst_i             (int_alu_wb_dst),
	.int_alu_wb_data_i            (int_alu_wb_data),

	.wb_valid_o                   (wb_valid),
	.wb_wid_o                     (wb_wid),
	.wb_dst_o                     (wb_dst),
	.wb_data_o                    (wb_data)
);


endmodule

`timescale 1ns/1ns
`include "../common/define.sv"

module sm_warp_scheduler (
	input  clk,                                               // input clock for the system
	input  rst_n,                                             // reset signal to the system, negative active

	output tpc_req_ready_o,                                   // signal telling whether sm core is ready to receive a new request from tpc
	input  tpc_req_valid_i,                                   // signal indicating a new kernel to be assigned to this sm core for execution
	input  tpc_rsp_ready_i,                                   // signal telling whether tpc is ready to receive response from this sm core
	output tpc_rsp_valid_o,                                   // signal indicating a new response is available for TPC's processing
	output [`DEPTH_WARP-1:0] tpc_rsp_wid_o,                   // warp id of a new completed warp

	output sm_warp_req_valid_o,                               // indiate a new warp is assigned for execution
	output [`DEPTH_WARP-1:0] sm_warp_req_wid_o,               // warp id of this new warp to be executed
	output sm_warp_rsp_ready_o,                               // signal telling whether it is ready to receive response from warp
	input  sm_warp_rsp_valid_i,                               // signal indicating a new response is available for processing
	input  [`DEPTH_WARP-1:0] sm_warp_rsp_wid_i	             // warp id of a new completed warp
);

wire tpc_req_fire, sm_warp_rsp_fire;
reg [`NUM_WARP-1:0]  bitmap_assigned;
wire [`NUM_WARP-1:0] bitmap_to_assign,bitmap_to_release;

wire [`DEPTH_WARP-1:0] index_to_assign;
wire [`NUM_WARP-1:0]   bitmap_to_assign_oh;

assign tpc_req_fire = tpc_req_valid_i && tpc_req_ready_o;
assign sm_warp_rsp_fire = sm_warp_rsp_valid_i && sm_warp_rsp_ready_o;

assign tpc_req_ready_o = ~(&bitmap_assigned);
assign bitmap_to_assign = bitmap_assigned | ((1'h1<<index_to_assign) & {`NUM_WARP{tpc_req_fire}}); 
assign bitmap_to_release = (1'h1<<sm_warp_rsp_wid_i) & {`NUM_WARP{sm_warp_rsp_fire}}; 

assign sm_warp_req_valid_o = tpc_req_fire;
assign sm_warp_req_wid_o = index_to_assign;

assign sm_warp_rsp_ready_o = tpc_rsp_ready_i;
assign tpc_rsp_valid_o = sm_warp_rsp_valid_i;
assign tpc_rsp_wid_o = sm_warp_rsp_wid_i;


always @(posedge clk or negedge rst_n) begin
	if(!rst_n) begin
		bitmap_assigned <= 'h0;
	end 
	else begin
		bitmap_assigned <= bitmap_to_assign;            //bitmap_to_assign & (~bitmap_to_release); 
	end  
end 


rr_arb #(
	.ARB_WIDTH(`NUM_WARP)
) assign_rr_arb (
	.clk                 (clk),
	.rst_n               (rst_n),
	.req_i               (tpc_req_fire?~bitmap_assigned:{`NUM_WARP{1'b0}}),
	.grant_o             (bitmap_to_assign_oh)
);


oh2bin #(
	.ONE_HOT_WIDTH(`NUM_WARP),
	.BIN_WIDTH(`DEPTH_WARP)
) assign_oh2bin (
	.oh_i                (bitmap_to_assign_oh),
	.bin_o               (index_to_assign)
);

endmodule

module sm_fetch (
	input  clk,                                               // input clock for the system
	input  rst_n, 

	input  sm_warp_req_valid_i,                               // indiate a new warp request is available
	input  [`DEPTH_WARP-1:0] sm_warp_req_wid_i,                                 // warp id of this new warp request
	input  [`CODE_ADDR_WIDTH-1:0] sm_warp_req_start_addr_i,   // starting address for kernel code
	input  [`NUM_WARP-1:0] ibuffer_avail_i,                   // indicate whether instruction buffer of this warp has free space
	input  [`NUM_WARP-1:0] stalled_warps_i,                   // tell the information of stalled warps

	output [`NUM_WARP-1:0] ready_warps_o,                     // indicate the warps that are ready for instruction fetch

	input  code_mem_ready_i,                                  // signal indicating whether external code memory is ready for access
	output code_rd_req_valid_o,                               // valid signal of code memory read operation
	output [`CODE_MEM_ADDR_WIDTH-1:0] code_rd_req_addr_o,     // code memory read address
	output [`DEPTH_WARP-1:0] code_rd_req_wid_o,               // warp id of code memory read,

   input  code_rd_rsp_valid_i,                               // indicate the response from external code memory is available
   input  [`CODE_MEM_ADDR_WIDTH-1:0] code_rd_rsp_addr_i,     // returned address of code memory response	
   input  [`DEPTH_WARP-1:0] code_rd_rsp_wid_i                // warp id of code memory response	
);

wire sm_warp_req_fire;
reg  [`NUM_WARP-1:0] active_warps;

wire [`DEPTH_WARP-1:0] selected_warp;
wire [`NUM_WARP-1:0]   selected_warp_oh;

reg  [`CODE_ADDR_WIDTH-1:0] warp_pcs[`NUM_WARP-1:0];
integer i;


assign sm_warp_req_fire = sm_warp_req_valid_i;

assign ready_warps_o = active_warps & ~stalled_warps_i;

wire [`NUM_WARP-1:0] fetch_eligible;
assign fetch_eligible = ready_warps_o & ibuffer_avail_i;

always @(posedge clk or negedge rst_n) begin
	if(!rst_n) begin
		active_warps <= 'h0;
	end 
	else begin
		active_warps <= active_warps | ((1'h1<< sm_warp_req_wid_i) & {`NUM_WARP{sm_warp_req_fire}});
	end 
end


rr_arb #(
	.ARB_WIDTH(`NUM_WARP)
) fetch_rr_arb (
	.clk                 (clk),
	.rst_n               (rst_n),
	.req_i               (fetch_eligible),
	.grant_o             (selected_warp_oh)
);


oh2bin #(
	.ONE_HOT_WIDTH(`NUM_WARP),
	.BIN_WIDTH(`DEPTH_WARP)
) fetch_oh2bin (
	.oh_i                (selected_warp_oh),
	.bin_o               (selected_warp)
);

always @(posedge clk or negedge rst_n) begin
	for(i=0;i<`NUM_WARP;i=i+1) begin
		if(!rst_n) begin
			warp_pcs[i] <= 'h0;
		end 
		else begin			
			warp_pcs[i] <= (sm_warp_req_fire && (i == sm_warp_req_wid_i)) ? sm_warp_req_start_addr_i :
								((fetch_eligible[i] && (i == selected_warp)) ? warp_pcs[i]+(`CODE_MEM_DATA_WIDTH >> 3): warp_pcs[i]);
		end
	end
end

assign code_rd_req_valid_o = (|fetch_eligible) && code_mem_ready_i;
assign code_rd_req_addr_o = warp_pcs[selected_warp];
assign code_rd_req_wid_o = selected_warp;


endmodule

`timescale 1ns/1ns
`include "../common/define.sv"

module sm_decode (
	input  clk,                                               // input clock for the system
	input  rst_n, 

	input  valid_i,                                           // indicate whether there is a valid instruction to be decoded
	input  [`CODE_MEM_DATA_WIDTH-1:0] inst_i,                 // input instruction to be decoded
	input  [`DEPTH_WARP-1:0] wid_i,                           // input warp id

	output [`CODE_MEM_DATA_WIDTH-1:0] decode_signals_inst_o,  // output instruction 
	output [`DEPTH_WARP-1:0] decode_signals_wid_o,            // output warp id
	output [3:0] decode_signals_opcode_na_o,                  // output opcode na field
	output [5:0] decode_signals_mod_o,                        // output mod field
	output [3:0] decode_signals_pr_o,                         // output pr field
	output [5:0] decode_signals_dst_o,                        // output dst field
	output [5:0] decode_signals_src1_o,                       // output src1 field
	output [19:0] decode_signals_immea_o,                     // output immea field
	output [1:0]  decode_signals_space_sel_o,                 // output space selector field
	output [9:0] decode_signals_immeb_o,                      // output immeb field	
	output [5:0] decode_signals_opcode_nb_o                   // output opcode nb field
);

assign decode_signals_inst_o = valid_i?inst_i:'h0;
assign decode_signals_wid_o = valid_i?wid_i:{`DEPTH_WARP{1'b0}};


// Ferimi GPU Instruction Encoding Format (8-Byte Instruction):
// Opcode NA: [3:0]
// Mod: [9:4]
// PR: [13:10]
// Dst Register: [19:14]
// Src1 Register: [25:20]
// Src2 Register: [31:26]
// Const Offset: [41:26], Const Bank [45:42]
// Immediate A Value: [45:26]
// Space Selector: [47:46]: 00-use SRC2, 01-use Const, 10-unused, 11-Immediate Value
// Src3 Register: [53:48]
// Immediate B Value: [57:48]
// Opcode NB: [63:58]

assign decode_signals_opcode_na_o = valid_i?inst_i[3:0]:4'h0;
assign decode_signals_mod_o = valid_i?inst_i[9:4]:6'h0;
assign decode_signals_pr_o = valid_i?inst_i[13:10]:4'h0;
assign decode_signals_dst_o = valid_i?inst_i[19:14]:6'h0;
assign decode_signals_src1_o = valid_i?inst_i[25:20]:6'h0;
assign decode_signals_immea_o = valid_i?inst_i[45:26]:20'h0;
assign decode_signals_space_sel_o = valid_i?inst_i[47:46]:2'h0;
assign decode_signals_immeb_o = valid_i?inst_i[57:48]:10'h0;
assign decode_signals_opcode_nb_o = valid_i?inst_i[63:58]:6'h0;

endmodule

`timescale 1ns/1ns
`include "../common/define.sv"

module sm_inst_buffer #(
	parameter IBUFFER_DATA_WIDTH = 2*`CODE_MEM_DATA_WIDTH+`DEPTH_WARP, 
	parameter IBUFFER_SIZE = 2
)
(
	input  clk,                                                // input clock for the system
	input  rst_n,                                              // reset signal

	input decode_signals_valid_i,                              // valid signal of decode signals	
	input [`CODE_MEM_DATA_WIDTH-1:0] decode_signals_inst_i,    // input decoded instruction 
	input [`DEPTH_WARP-1:0] decode_signals_wid_i,              // input warp id
	input [3:0] decode_signals_opcode_na_i,                    // input opcode na field
	input [5:0] decode_signals_mod_i,                          // input mod field
	input [3:0] decode_signals_pr_i,                           // input pr field
	input [5:0] decode_signals_dst_i,                          // input dst field
	input [5:0] decode_signals_src1_i,                         // input src1 field
	input [19:0] decode_signals_immea_i,                       // input immea field
	input [1:0] decode_signals_space_sel_i,                    // input space_sel field
	input [9:0] decode_signals_immeb_i,                        // input immeb field	
	input [5:0] decode_signals_opcode_nb_i,                    // input opcode nb field

	output [`CODE_MEM_DATA_WIDTH-1:0] ibuffer_signals_inst_o,  // output instruction 
	output [`DEPTH_WARP-1:0] ibuffer_signals_wid_o,            // output warp id
	output [3:0] ibuffer_signals_opcode_na_o,                  // output opcode na field
	output [5:0] ibuffer_signals_mod_o,                        // output mod field
	output [3:0] ibuffer_signals_pr_o,                         // output pr field
	output [5:0] ibuffer_signals_dst_o,                        // output dst field
	output [5:0] ibuffer_signals_src1_o,                       // output src1 field
	output [19:0] ibuffer_signals_immea_o,                     // output immea field
	output [1:0] ibuffer_signals_space_sel_o,                  // output space_sel field
	output [9:0] ibuffer_signals_immeb_o,                      // output immeb field	
	output [5:0] ibuffer_signals_opcode_nb_o,                  // output opcode nb field	
	output ibuffer_signals_valid_o,                            // valid signal of decode signals	

	input  [`NUM_WARP-1:0] ready_warps_i,                      // indicate the warps that are ready for instruction fetch
	output [`NUM_WARP-1:0] ibuffer_avail_o                     // instruction buffer available flag
);

wire [`NUM_WARP-1:0] rd_en, wr_en;
wire [`NUM_WARP-1:0] full;
wire [`NUM_WARP-1:0] empty;

wire  [IBUFFER_DATA_WIDTH-1:0] wr_data;
wire  [IBUFFER_DATA_WIDTH-1:0] rd_data[`NUM_WARP-1:0];
wire [`NUM_WARP-1:0] rd_data_valid;

wire [`NUM_WARP-1:0] ibuffer_has_data;
wire [`NUM_WARP-1:0] ibuffer_to_issue_oh;
wire [`DEPTH_WARP-1:0] ibuffer_to_issue;

assign rd_en = ibuffer_to_issue_oh;
assign wr_en = (~full[decode_signals_wid_i] && decode_signals_valid_i) ? (`NUM_WARP'b1 << decode_signals_wid_i) : `NUM_WARP'b0;

assign wr_data = 
			{
				decode_signals_inst_i,
				decode_signals_wid_i,
				decode_signals_opcode_nb_i,
				decode_signals_immeb_i,
				decode_signals_space_sel_i,
				decode_signals_immea_i,	
				decode_signals_src1_i,				
				decode_signals_dst_i,				
				decode_signals_pr_i,
				decode_signals_mod_i,
				decode_signals_opcode_na_i				
			};


genvar i; 
generate
	for(i=0;i<`NUM_WARP;i=i+1) begin: inst_buffer_per_warp	
		sync_fifo #(
			.DATA_WIDTH(IBUFFER_DATA_WIDTH),
			.FIFO_DEPTH(IBUFFER_SIZE)
		) U_sync_fifo (
			.clk               (clk),
			.rst_n             (rst_n),
			.rd_en_i           (rd_en[i]),
			.rd_data_o         (rd_data[i]),
			.rd_valid_o        (rd_data_valid[i]),
			.wr_en_i           (wr_en[i]),
			.wr_data_i         (wr_data),
			.empty_o           (empty[i]),
			.full_o            (full[i])
		);	
	end
endgenerate

assign ibuffer_signals_opcode_na_o = rd_data[ibuffer_to_issue][3:0];
assign ibuffer_signals_mod_o = rd_data[ibuffer_to_issue][9:4];
assign ibuffer_signals_pr_o = rd_data[ibuffer_to_issue][13:10];
assign ibuffer_signals_dst_o = rd_data[ibuffer_to_issue][19:14];			
assign ibuffer_signals_src1_o = rd_data[ibuffer_to_issue][25:20];
assign ibuffer_signals_immea_o = rd_data[ibuffer_to_issue][45:26];
assign ibuffer_signals_space_sel_o = rd_data[ibuffer_to_issue][47:46];
assign ibuffer_signals_immeb_o = rd_data[ibuffer_to_issue][57:48];
assign ibuffer_signals_opcode_nb_o = rd_data[ibuffer_to_issue][63:58];
assign ibuffer_signals_wid_o = rd_data[ibuffer_to_issue][64+:`DEPTH_WARP];	
assign ibuffer_signals_inst_o = rd_data[ibuffer_to_issue][IBUFFER_DATA_WIDTH-1 -:`CODE_MEM_DATA_WIDTH];

assign ibuffer_signals_valid_o = rd_data_valid[ibuffer_to_issue];
assign ibuffer_has_data = (~empty) & ready_warps_i;
assign ibuffer_avail_o = ~full;

rr_arb #(
	.ARB_WIDTH(`NUM_WARP)
) ibuffer_rr_arb (
	.clk                 (clk),
	.rst_n               (rst_n),
	.req_i               (ibuffer_has_data),
	.grant_o             (ibuffer_to_issue_oh)
);

oh2bin #(
	.ONE_HOT_WIDTH(`NUM_WARP),
	.BIN_WIDTH(`DEPTH_WARP)
) fetch_oh2bin (
	.oh_i                (ibuffer_to_issue_oh),
	.bin_o               (ibuffer_to_issue)
);

endmodule

`timescale 1ns/1ns
`include "../common/define.sv"

module sm_score_board (
	input  clk,
	input  rst_n,

	// input from instruction buffer
	input  ibuffer_signals_valid_i,
	input  [`CODE_MEM_DATA_WIDTH-1:0] ibuffer_signals_inst_i,
	input  [`DEPTH_WARP-1:0] ibuffer_signals_wid_i,
	input  [3:0] ibuffer_signals_opcode_na_i,
	input  [5:0] ibuffer_signals_mod_i,
	input  [3:0] ibuffer_signals_pr_i,
	input  [5:0] ibuffer_signals_dst_i,
	input  [5:0] ibuffer_signals_src1_i,
	input  [19:0] ibuffer_signals_immea_i,
	input  [1:0] ibuffer_signals_space_sel_i,
	input  [9:0] ibuffer_signals_immeb_i,
	input  [5:0] ibuffer_signals_opcode_nb_i,

	// writeback completion to clear in-flight registers
	input  wb_valid_i,
	input  [`DEPTH_WARP-1:0] wb_wid_i,
	input  [5:0] wb_dst_i,

	// output to operand collect
	output sb_signals_valid_o,
	output [`CODE_MEM_DATA_WIDTH-1:0] sb_signals_inst_o,
	output [`DEPTH_WARP-1:0] sb_signals_wid_o,
	output [3:0] sb_signals_opcode_na_o,
	output [5:0] sb_signals_mod_o,
	output [3:0] sb_signals_pr_o,
	output [5:0] sb_signals_dst_o,
	output [5:0] sb_signals_src1_o,
	output [19:0] sb_signals_immea_o,
	output [1:0] sb_signals_space_sel_o,
	output [9:0] sb_signals_immeb_o,
	output [5:0] sb_signals_opcode_nb_o,

	// stalled warps bitmap to fetch stage
	output [`NUM_WARP-1:0] stalled_warps_o
);

// per-warp in-flight destination register tracking
// each warp has a 64-bit bitmap (6-bit register address -> 64 registers)
reg [`NUM_REG-1:0] inflight_regs [`NUM_WARP-1:0];

wire [5:0] src1 = ibuffer_signals_src1_i;
wire [5:0] src2 = ibuffer_signals_immea_i[5:0]; // src2 is in bits [31:26] of instruction, mapped to immea[5:0]
wire [5:0] dst  = ibuffer_signals_dst_i;
wire [`DEPTH_WARP-1:0] wid = ibuffer_signals_wid_i;

// space_sel == 2'b00 means src2 is a register operand
wire src2_is_reg = (ibuffer_signals_space_sel_i == 2'b00);

// check for RAW hazards: source registers conflict with in-flight destinations
wire src1_hazard = inflight_regs[wid][src1];
wire src2_hazard = src2_is_reg && inflight_regs[wid][src2];
wire has_hazard  = ibuffer_signals_valid_i && (src1_hazard || src2_hazard);

// issue the instruction only when there is no hazard
wire issue_valid = ibuffer_signals_valid_i && !has_hazard;

// generate stalled_warps bitmap
genvar w;
generate
	for (w = 0; w < `NUM_WARP; w = w + 1) begin: stall_check
		assign stalled_warps_o[w] = (|inflight_regs[w]);
	end
endgenerate

// update in-flight register tracking
integer i;
always @(posedge clk or negedge rst_n) begin
	for (i = 0; i < `NUM_WARP; i = i + 1) begin
		if (!rst_n) begin
			inflight_regs[i] <= {`NUM_REG{1'b0}};
		end
		else begin
			if (issue_valid && (i == wid) && wb_valid_i && (i == wb_wid_i))
				inflight_regs[i] <= (inflight_regs[i] | ({{(`NUM_REG-1){1'b0}}, 1'b1} << dst)) & ~({{(`NUM_REG-1){1'b0}}, 1'b1} << wb_dst_i);
			else if (issue_valid && (i == wid))
				inflight_regs[i] <= inflight_regs[i] | ({{(`NUM_REG-1){1'b0}}, 1'b1} << dst);
			else if (wb_valid_i && (i == wb_wid_i))
				inflight_regs[i] <= inflight_regs[i] & ~({{(`NUM_REG-1){1'b0}}, 1'b1} << wb_dst_i);
		end
	end
end

// pass-through signals to operand collect
assign sb_signals_valid_o      = issue_valid;
assign sb_signals_inst_o       = ibuffer_signals_inst_i;
assign sb_signals_wid_o        = ibuffer_signals_wid_i;
assign sb_signals_opcode_na_o  = ibuffer_signals_opcode_na_i;
assign sb_signals_mod_o        = ibuffer_signals_mod_i;
assign sb_signals_pr_o         = ibuffer_signals_pr_i;
assign sb_signals_dst_o        = ibuffer_signals_dst_i;
assign sb_signals_src1_o       = ibuffer_signals_src1_i;
assign sb_signals_immea_o      = ibuffer_signals_immea_i;
assign sb_signals_space_sel_o  = ibuffer_signals_space_sel_i;
assign sb_signals_immeb_o      = ibuffer_signals_immeb_i;
assign sb_signals_opcode_nb_o  = ibuffer_signals_opcode_nb_i;

endmodule

