`timescale 1ns/1ns
`include "define.sv"

module rr_arb #(
	parameter ARB_WIDTH = 8
)
(
	input  clk,                                               // input clock for the system
	input  rst_n,

	input  [ARB_WIDTH-1:0] req_i ,
	output [ARB_WIDTH-1:0] grant_o
);

reg [ARB_WIDTH-1:0] cur_pri;

always @(posedge clk or negedge rst_n) begin
	if(!rst_n) begin      
		cur_pri <= {{(ARB_WIDTH-1){1'b0}},1'b1};
	end 
	else if(|req_i) begin
		cur_pri <= {grant_o[ARB_WIDTH-2:0], grant_o[ARB_WIDTH-1]};
	end 
	else begin      
		cur_pri <= cur_pri;
	end
end



fixed_pri_arb_base #(
  .ARB_WIDTH(ARB_WIDTH)
) arb_base (
  .req_i      (req_i),
  .pri_i      (cur_pri),
  .grant_o    (grant_o)
);

endmodule

`timescale 1ns/1ns
`include "define.sv"

module fixed_pri_arb #(
	parameter ARB_WIDTH = 8
)
(
	input  [ARB_WIDTH-1:0] req_i ,
	output [ARB_WIDTH-1:0] grant_o
);

wire [ARB_WIDTH-1:0] pre_req;

assign pre_req[0] = 1'b0;
assign pre_req[ARB_WIDTH-1:1] = req_i[ARB_WIDTH-2:0] | pre_req[ARB_WIDTH-2:0];
assign grant_o = req_i & (~pre_req);

endmodule

`timescale 1ns/1ns
`include "define.sv"

module fixed_pri_arb_base #(
	parameter ARB_WIDTH = 8
)
(
	input  [ARB_WIDTH-1:0] req_i ,
	input  [ARB_WIDTH-1:0] pri_i ,
	output [ARB_WIDTH-1:0] grant_o
);

wire [2*ARB_WIDTH-1:0] double_grant;

assign double_grant = {req_i,req_i} & ~({req_i,req_i}-pri_i);
assign grant_o = double_grant[2*ARB_WIDTH-1:ARB_WIDTH] | double_grant[ARB_WIDTH-1:0];

endmodule

