4	module sync_fifo #(
5		parameter DATA_WIDTH = 64,
6		parameter FIFO_DEPTH = 4
7	)
8	(
9		input  clk,                                               // input clock for the system
10		input  rst_n,                                             // reset signal, negative active
11		
12		input  rd_en_i,                                           // fifo read enable signal
13		output reg [DATA_WIDTH-1:0] rd_data_o,                    // read data from fifo
14		output reg rd_valid_o,                                    // fifo read data valid signal	
15		input  wr_en_i,                                           // fifo write enable signal
16		input  [DATA_WIDTH-1:0] wr_data_i,                        // write data to fifo
17		output empty_o,                                           // fifo empty flag
18		output full_o	                                          // fifo full flag
19	);
20	
21	localparam ADDR_WIDTH = $clog2(FIFO_DEPTH);
22	
23	reg [DATA_WIDTH-1:0] fifo_data [FIFO_DEPTH-1:0];
24	reg [ADDR_WIDTH:0] rd_ptr;
25	reg [ADDR_WIDTH:0] wr_ptr;
26	
27	wire [ADDR_WIDTH-1:0] rd_ptr_true;
28	wire [ADDR_WIDTH-1:0] wr_ptr_true;
29	
30	wire rd_ptr_msb;
31	wire wr_ptr_msb;
32	
33	assign {rd_ptr_msb, rd_ptr_true} = rd_ptr;
34	assign {wr_ptr_msb, wr_ptr_true} = wr_ptr;
35	
36	always @(posedge clk or negedge rst_n) begin
37		if(!rst_n) begin
38	    	rd_ptr <= 'd0;
39			rd_data_o <= 'h0;
40			rd_valid_o <= 1'b0;
41	    end
42	    else if(rd_en_i && !empty_o) begin
43			rd_data_o <= fifo_data[rd_ptr_true];
44	    	rd_ptr <= rd_ptr + {{ADDR_WIDTH{1'b0}}, 1'b1};
45			rd_valid_o <= 1'b1;
46	    end
47	    else begin
48	    	rd_ptr <= rd_ptr;
49			rd_data_o <= 'h0;
50			rd_valid_o <= 1'b0;
51	    end
52	
53	end
54	
55	genvar i;
56	generate
57		for (i = 0; i < FIFO_DEPTH; i = i + 1) begin: fifo_data_reg
58			always @(posedge clk or negedge rst_n) begin
59				if(!rst_n) begin
60					fifo_data[i] <= {DATA_WIDTH{1'b0}};
61				end
62				else if(wr_en_i && !full_o && (wr_ptr_true == i[ADDR_WIDTH-1:0])) begin
63					fifo_data[i] <= wr_data_i;
64				end
65			end
66		end
67	endgenerate
68	
69	always @(posedge clk or negedge rst_n) begin
70		if(!rst_n) begin
71	    	wr_ptr <= 'd0;
72	    end
73	    else if(wr_en_i && !full_o) begin
74	    	wr_ptr <= wr_ptr + {{ADDR_WIDTH{1'b0}}, 1'b1};
75	    end
76	    else begin
77	    	wr_ptr <= wr_ptr;
78	    end
79	
80	end
81	
82	assign empty_o = (wr_ptr == rd_ptr)?1'b1:1'b0;
83	assign full_o = ((wr_ptr_msb != rd_ptr_msb) && (wr_ptr_true == rd_ptr_true))?1'b1:1'b0;
84	
85	endmodule

