`timescale 1ns/1ns
`include "define.sv"

module sync_fifo #(
	parameter DATA_WIDTH = 64,
	parameter FIFO_DEPTH = 4
)
(
	input  clk,                                               // input clock for the system
	input  rst_n,                                             // reset signal, negative active

	input  rd_en_i,                                           // fifo read enable signal
	output reg [DATA_WIDTH-1:0] rd_data_o,                    // read data from fifo
	output reg rd_valid_o,                                    // fifo read data valid signal	
	input  wr_en_i,                                           // fifo write enable signal
	input  [DATA_WIDTH-1:0] wr_data_i,                        // write data to fifo
	output empty_o,                                           // fifo empty flag
	output full_o	                                          // fifo full flag
);

localparam ADDR_WIDTH = $clog2(FIFO_DEPTH);

reg [DATA_WIDTH-1:0] fifo_data [FIFO_DEPTH-1:0];
reg [ADDR_WIDTH:0] rd_ptr;
reg [ADDR_WIDTH:0] wr_ptr;

wire [ADDR_WIDTH-1:0] rd_ptr_true;
wire [ADDR_WIDTH-1:0] wr_ptr_true;

wire rd_ptr_msb;
wire wr_ptr_msb;

assign {rd_ptr_msb, rd_ptr_true} = rd_ptr;
assign {wr_ptr_msb, wr_ptr_true} = wr_ptr;

always @(posedge clk or negedge rst_n) begin
	if(!rst_n) begin
    	rd_ptr <= 'd0;
		rd_data_o <= 'h0;
		rd_valid_o <= 1'b0;
    end
    else if(rd_en_i && !empty_o) begin
		rd_data_o <= fifo_data[rd_ptr_true];
    	rd_ptr <= rd_ptr + {{ADDR_WIDTH{1'b0}}, 1'b1};
		rd_valid_o <= 1'b1;
    end
    else begin
    	rd_ptr <= rd_ptr;
		rd_data_o <= 'h0;
		rd_valid_o <= 1'b0;
    end

end

genvar i;
generate
	for (i = 0; i < FIFO_DEPTH; i = i + 1) begin: fifo_data_reg
		always @(posedge clk or negedge rst_n) begin
			if(!rst_n) begin
				fifo_data[i] <= {DATA_WIDTH{1'b0}};
			end
			else if(wr_en_i && !full_o && (wr_ptr_true == i[ADDR_WIDTH-1:0])) begin
				fifo_data[i] <= wr_data_i;
			end
		end
	end
endgenerate

always @(posedge clk or negedge rst_n) begin
	if(!rst_n) begin
    	wr_ptr <= 'd0;
    end
    else if(wr_en_i && !full_o) begin
    	wr_ptr <= wr_ptr + {{ADDR_WIDTH{1'b0}}, 1'b1};
    end
    else begin
    	wr_ptr <= wr_ptr;
    end

end

assign empty_o = (wr_ptr == rd_ptr)?1'b1:1'b0;
assign full_o = ((wr_ptr_msb != rd_ptr_msb) && (wr_ptr_true == rd_ptr_true))?1'b1:1'b0;

endmodule

`timescale 1ns/1ns
`include "define.sv"

module sync_fifo_count #(
	parameter DATA_WIDTH = 64,
	parameter FIFO_DEPTH = 4
)
(
	input  clk,                                               // input clock for the system
	input  rst_n,                                             // reset signal, negative active

	input  rd_en_i,                                           // fifo read enable signal
	output [DATA_WIDTH-1:0] rd_data_o,                        // read data from fifo
	input  wr_en_i,                                           // fifo write enable signal
	input  [DATA_WIDTH-1:0] wr_data_i,                        // write data to fifo
	output empty_o,                                           // fifo empty flag
	output full_o,	                                           // fifo full flag
	output reg [$clog2(FIFO_DEPTH):0] fifo_count_o            // fifo count
);

reg [DATA_WIDTH-1:0] fifo_data [FIFO_DEPTH-1:0];
reg [$clog2(FIFO_DEPTH)-1:0] rd_addr;
reg [$clog2(FIFO_DEPTH)-1:0] wr_addr;


always @(posedge clk or negedge rst_n) begin
	if(!rst_n) begin
      rd_addr <= 'd0;
    end
    else if(rd_en_i && !empty_o) begin
		rd_data_o <= fifo_data[rd_addr];
      rd_addr <= rd_addr + 1;
    end
    else begin
      rd_addr <= rd_addr;
    end

end


always @(posedge clk or negedge rst_n) begin
	if(!rst_n) begin
      wr_addr <= 'd0;
		fifo_data <='{default:'h0};
    end
    else if(wr_en_i && !full_o) begin
		fifo_data[wr_addr] <= wr_data_i;
      wr_addr <= wr_addr + 1;
    end
    else begin
      wr_addr <= wr_addr;
    end

end


always @(posedge clk or negedge rst_n) begin
	if(!rst_n) begin
      fifo_count_o <= 0;
    end
    else begin
      case ({rd_en_i, wr_en_i})
			2'b00:fifo_count_o <= fifo_count_o;
			2'b10:
				if (fifo_count_o != 0)
					fifo_count_o <= fifo_count_o-1;
			2'b01:
				if (fifo_count_o != FIFO_DEPTH)
					fifo_count_o <= fifo_count_o+1;
			2'b11:fifo_count_o <= fifo_count_o;
			default:fifo_count_o <= fifo_count_o;
		endcase
    end

end

assign empty_o = (fifo_count_o == 0)?1'b1:1'b0;
assign full_o = (fifo_count_o == FIFO_DEPTH)?1'b1:1'b0;

endmodule

import os
import sys
from datetime import datetime

class Logger:
    def __init__(self, log_dir="logs", encoding='utf-8'):
        if not os.path.exists(log_dir):
            try:
                os.makedirs(log_dir)
            except Exception as e:
                print(f"creating log folder failed: {e}")  
                log_dir = "." 
        self.filename = os.path.join(log_dir, f"log_{datetime.now().strftime('%Y%m%d%H%M%S')}.txt")
        self.encoding = encoding

    def log(self, *messages):
        complete_message = ' '.join(str(message) for message in messages)
        with open(self.filename, "a", encoding=self.encoding) as f:
            f.write(complete_message + "\n")

logger = Logger(log_dir="test/logs")
